// // This module implements an 8-bit shift register with parallel load.
// When the LOAD signal is low, the data D is loaded into the register Q.
// When the SHIFT signal is low, the register Q shifts right by one bit.
module shift_register_8bit (D, CLK, LOAD, SHIFT, Q);
input [7:0] D;
input CLK, LOAD, SHIFT;
output reg [7:0] Q;

always @(posedge CLK) begin
    if (LOAD) begin
        Q <= D;
    end
    else if (SHIFT) begin
        Q <= Q << 1;
    end
end

endmodule

